import { Component, Input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';

export interface BookCard {
  id: number;
  title: string;
  author: string;
  price: number;
  condition: string;
  book_type: string;
  images: { url: string; is_primary: boolean }[];
  seller: { first_name: string; last_name: string; phone: string; address?: string };
  category?: { name: string };
  is_available: boolean;
}

@Component({
  selector: 'app-book-card',
  standalone: true,
  imports: [RouterLink, CommonModule],
  templateUrl: './book-card.component.html',
})
export class BookCardComponent {
  @Input() book!: BookCard;

  get conditionLabel(): string {
    const map: Record<string, string> = { new: 'Neuf', like_new: 'Très bon', good: 'Bon état', fair: 'Correct' };
    return map[this.book.condition] || this.book.condition;
  }

  get conditionClass(): string {
    const map: Record<string, string> = {
      new: 'bg-green-100 text-green-700',
      like_new: 'bg-blue-100 text-blue-700',
      good: 'bg-amber-100 text-amber-700',
      fair: 'bg-gray-100 text-gray-600',
    };
    return map[this.book.condition] || 'bg-gray-100 text-gray-600';
  }

  get primaryImage(): string {
    const img = this.book.images?.find(i => i.is_primary) || this.book.images?.[0];
    return img?.url || '/assets/book-placeholder.svg';
  }
}
